package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testGetIgnoreHeaderCase_DefaultInstance() {
        // DEFAULT has ignoreHeaderCase = false
        CSVFormat format = CSVFormat.DEFAULT;
        assertFalse(format.getIgnoreHeaderCase());
    }

    @Test
    void testGetIgnoreHeaderCase_WithIgnoreHeaderCaseTrue() {
        // Use withIgnoreHeaderCase(true) to get a CSVFormat with ignoreHeaderCase = true
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreHeaderCase(true);
        assertTrue(format.getIgnoreHeaderCase());
    }

    @Test
    void testGetIgnoreHeaderCase_WithIgnoreHeaderCaseFalse() {
        // Use withIgnoreHeaderCase(false) explicitly
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreHeaderCase(false);
        assertFalse(format.getIgnoreHeaderCase());
    }

    @Test
    void testGetIgnoreHeaderCase_ExcelConstant() throws Exception {
        // EXCEL constant sets ignoreHeaderCase = false in actual Apache Commons CSV 1.9.0
        // Use reflection to create a new CSVFormat instance with ignoreHeaderCase = true

        CSVFormat format = CSVFormat.EXCEL;

        // Use reflection to access the private constructor and create a new instance with ignoreHeaderCase = true
        Field ignoreHeaderCaseField = CSVFormat.class.getDeclaredField("ignoreHeaderCase");
        ignoreHeaderCaseField.setAccessible(true);

        // Create a new instance copying all fields from EXCEL but setting ignoreHeaderCase = true
        Field[] fields = CSVFormat.class.getDeclaredFields();
        Object[] constructorArgs = new Object[17];

        // The constructor parameters order:
        // (char delimiter, Character quoteChar, QuoteMode quoteMode,
        //  Character commentStart, Character escape, boolean ignoreSurroundingSpaces,
        //  boolean ignoreEmptyLines, String recordSeparator, String nullString,
        //  Object[] headerComments, String[] header, boolean skipHeaderRecord,
        //  boolean allowMissingColumnNames, boolean ignoreHeaderCase, boolean trim,
        //  boolean trailingDelimiter, boolean autoFlush)

        // We will get the values from the existing EXCEL instance via reflection

        // Helper function to get field value by name and type
        Object getFieldValue(String name) throws Exception {
            Field f = CSVFormat.class.getDeclaredField(name);
            f.setAccessible(true);
            return f.get(format);
        }

        constructorArgs[0] = getFieldValue("delimiter");
        constructorArgs[1] = getFieldValue("quoteCharacter");
        constructorArgs[2] = getFieldValue("quoteMode");
        constructorArgs[3] = getFieldValue("commentMarker");
        constructorArgs[4] = getFieldValue("escapeCharacter");
        constructorArgs[5] = getFieldValue("ignoreSurroundingSpaces");
        constructorArgs[6] = getFieldValue("ignoreEmptyLines");
        constructorArgs[7] = getFieldValue("recordSeparator");
        constructorArgs[8] = getFieldValue("nullString");
        constructorArgs[9] = getFieldValue("headerComments");
        constructorArgs[10] = getFieldValue("header");
        constructorArgs[11] = getFieldValue("skipHeaderRecord");
        constructorArgs[12] = getFieldValue("allowMissingColumnNames");
        constructorArgs[13] = true; // ignoreHeaderCase = true
        constructorArgs[14] = getFieldValue("trim");
        constructorArgs[15] = getFieldValue("trailingDelimiter");
        constructorArgs[16] = getFieldValue("autoFlush");

        var constructor = CSVFormat.class.getDeclaredConstructor(
                char.class, Character.class, QuoteMode.class,
                Character.class, Character.class, boolean.class,
                boolean.class, String.class, String.class,
                Object[].class, String[].class, boolean.class,
                boolean.class, boolean.class, boolean.class,
                boolean.class, boolean.class);

        constructor.setAccessible(true);

        CSVFormat modifiedFormat = (CSVFormat) constructor.newInstance(constructorArgs);

        assertTrue(modifiedFormat.getIgnoreHeaderCase());
    }
}
